SELECT COUNT(*) FROM team2_db.TB_PJT_BASC
(PJT_NM LIKE CONCAT('%', #{keyword}, '%') OR employeeId LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY PJT_SN DESC LIMIT #{offset}, #{pageSize}

SELECT B.PJT_SN, B.PJT_NM, B.PJT_STTS_CD, B.employeeId, -- 담당자 (문자열) B.FRST_REG_DT, B.LAST_MDFCN_DT, B.PJT_BGNG_DT, B.PJT_END_DT FROM TB_PJT_BASC B WHERE (B.USE_YN IS NULL OR B.USE_YN = 'Y') -- NULL 허용 시 안전
AND ( B.PJT_NM LIKE CONCAT('%', #{param.keyword}, '%') OR B.employeeId LIKE CONCAT('%', #{param.keyword}, '%') )
AND B.employeeId = #{param.employeeId}
ORDER BY B.LAST_MDFCN_DT DESC, B.PJT_SN DESC LIMIT #{param.pageSize} OFFSET ${(param.pageNum-1)*param.pageSize}

